class efuAI {
    constructor() {
        // 初始化类属性
        this.root = "https://summary.tianli0.top";
        this.aiTalkMode = false;
        this.aiPostExplanation = '';
        this.config = GLOBAL_CONFIG.post_ai;
        this.scoGPTIsRunning = false;
    }

    init() {
        // 如果页面不存在AI解释元素，则返回
        if (!document.querySelector(".ai-explanation")) return;

        this.scoGPTIsRunning = false;
        
        // 获取页面配置中的AI解释文本
        this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text : false;

        // 如果没有AI解释文本，则生成
        if (!this.aiPostExplanation) {
            this.generate();
        } else {
            // 否则直接显示
            this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
        }

        // 初始化AI引擎
        this.AIEngine();
    }

    getTitleAndContent() {
        const container = document.getElementById("article-container");
        const title = document.title;
        const paragraphs = container.getElementsByTagName("p");
        const headings = container.querySelectorAll("h1, h2, h3, h4, h5");

        // 提取标题和内容，并进行处理
        return (title + Array.from(headings)
            .concat(Array.from(paragraphs))
            .map(e => e.innerText.replace(/https?:\/\/[^\s]+/g, ""))
            .join(" "))
            .slice(0, 1000);
    }

    async generate() {
        // 显示生成动画，并发起请求
        this.aiShowAnimation(this.fetch(document.title, this.getTitleAndContent(), this.config.key));
    }

    async fetch(title, content, key) {
        const url = `${this.root}/?content=${encodeURIComponent(content)}&title=${title}&key=${encodeURIComponent(key)}&url=${encodeURIComponent(window.location.href)}`;
        const response = await fetch(url);
        const data = await response.json();

        // 检查请求是否成功
        if (response.ok) {
            this.aiPostExplanation = data.summary;
            return data.summary;
        } else {
            console.error("Request failed:", data.err_msg);
            return data.err_msg;
        }
    }

    aiShowAnimation(promise, isSuggestion = false) {
        const explanationElement = document.querySelector(".ai-explanation");
        const tagElement = document.querySelector(".ai-tag");

        // 检查元素是否存在及运行状态
        if (!explanationElement || this.scoGPTIsRunning) return;

        this.scoGPTIsRunning = true;
        this.cleanSuggestions();
        tagElement.classList.add("loadingAI");
        explanationElement.style.display = "block";
        explanationElement.innerHTML = '生成中...<span class="blinking-cursor"></span>';

        let text, animationFrame, startTime, charIndex = 0, isIntersecting = true, hasStarted = true;
        const observer = new IntersectionObserver(entries => {
            isIntersecting = entries[0].isIntersecting;
            isIntersecting && requestAnimationFrame(animationFrame);
        }, { threshold: 0 });

        promise.then(data => {
            text = data;
            startTime = performance.now();
            animationFrame = () => {
                if (charIndex < text.length && isIntersecting) {
                    const currentTime = performance.now();
                    const timeDiff = currentTime - startTime;
                    const currentChar = text[charIndex];
                    const isPunctuation = /[，。！、？,.!?]/.test(currentChar);
                    const isAlphanumeric = /[a-zA-Z0-9]/.test(currentChar);

                    if (timeDiff >= (isPunctuation ? 100 * Math.random() + 100 : isAlphanumeric ? 10 : 25)) {
                        explanationElement.innerText = text.slice(0, charIndex + 1);
                        startTime = currentTime;
                        charIndex++;
                        if (charIndex < text.length) {
                            explanationElement.innerHTML = text.slice(0, charIndex) + '<span class="blinking-cursor"></span>';
                        } else {
                            explanationElement.innerHTML = text;
                            explanationElement.style.display = "block";
                            this.scoGPTIsRunning = false;
                            tagElement.classList.remove("loadingAI");
                            observer.disconnect();
                            if (isSuggestion) this.createSuggestions();
                        }
                    }
                }
                isIntersecting && requestAnimationFrame(animationFrame);
            };

            if (isIntersecting && hasStarted) {
                setTimeout(() => {
                    requestAnimationFrame(animationFrame);
                    hasStarted = false;
                }, 3000);
            }

            observer.observe(explanationElement);
        }).catch(error => {
            console.error("检索信息失败：", error);
            explanationElement.innerHTML = "检索信息失败";
            explanationElement.style.display = "block";
            this.scoGPTIsRunning = false;
            tagElement.classList.remove("loadingAI");
            observer.disconnect();
        });
    }

    AIEngine() {
        const tagElement = document.querySelector(".ai-tag");
        if (tagElement) {
            tagElement.addEventListener("click", () => {
                if (!this.scoGPTIsRunning) {
                    this.aiTalkMode = true;
                    this.aiShowAnimation(Promise.resolve(this.config.talk), true);
                }
            });
        }
    }

    cleanSuggestions() {
        const suggestionsElement = document.querySelector(".ai-suggestions");
        if (suggestionsElement) {
            suggestionsElement.innerHTML = "";
        } else {
            console.error("没有这个元素：'ai-suggestions'");
        }
    }

    createSuggestions() {
        if (this.aiTalkMode) {
            this.cleanSuggestions();
            this.createSuggestionItemWithAction("这篇文章讲了什么？", () => {
                if (this.aiPostExplanation === "") {
                    this.generate();
                } else {
                    this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
                }
            });
            if (this.config.randomPost) {
                this.createSuggestionItemWithAction("带我去看看其他文章", () => toRandomPost());
            }
            this.aiTalkMode = true;
        }
    }

    createSuggestionItemWithAction(text, action) {
        const suggestionsElement = document.querySelector(".ai-suggestions");
        if (!suggestionsElement) {
            console.error("无法找到具有class为ai-suggestions的元素");
            return;
        }

        const item = document.createElement("div");
        item.classList.add("ai-suggestions-item");
        item.textContent = text;
        item.addEventListener("click", action);
        suggestionsElement.appendChild(item);
    }
}

const efu_ai = new efuAI();